import math

class HybridScorer:
    def encode_dense(self, text):
        text = text.lower()
        vec = {}
        for i in range(len(text) - 2):
            g = text[i:i+3]
            vec[g] = vec.get(g, 0) + 1
        return vec

    def encode_sparse(self, text):
        words = text.lower().split()
        freq = {}
        for w in words:
            freq[w] = freq.get(w, 0) + 1
        return freq

    def cosine_sim(self, a, b):
        shared = set(a) & set(b)
        dot = sum(a[k] * b[k] for k in shared)
        ma = math.sqrt(sum(v**2 for v in a.values()))
        mb = math.sqrt(sum(v**2 for v in b.values()))
        return dot / (ma * mb) if ma and mb else 0.0

    def dense_score(self, a, b):
        return self.cosine_sim(self.encode_dense(a), self.encode_dense(b))

    def sparse_score(self, a, b):
        sa, sb = self.encode_sparse(a), self.encode_sparse(b)
        return sum(sa[k] * sb[k] for k in set(sa) & set(sb))

    def hybrid_score(self, a, b, dw=0.6, sw=0.4):
        return dw * self.dense_score(a, b) + sw * self.sparse_score(a, b)

